window.__QUIZ_DATA__=[{"id":"theory>Biology Practical>2007>1>a","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"a","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Specimen A is a food mixture. Carry out the instructions given in 1(a)(i) to 1(a)(iii) and record your observations and inferences as shown in the format of the Table below:    TESTOBSERVATIONINFERENCE  (i) Put a drop of A on a white tile and add a few drops of iodine solution. Record your observation and inference. (ii) Put 2 cm\u00b3 of A in a test tube and add 1 cm\u00b3 of sodium hydroxide solution and shake the mixture. Add 1.0% copper (II) sulphate solution drop by drop to the mixture in the test tube. Shakes the tube after each drop and record your observation and inference. (iii) Smear a drop of the mixture A on a piece of white paper, hold the paper against the light, record your observation and inference","images":[],"marking_scheme":"TESTOBSERVATIONINFERENCEi. Add a few drops of iodine solution to mixture A on a white tileBlue black colour was observedStarch is presentii. Add 1cm3 of sodium hydroxide to 2cm3 of mixture A in a test tube; shake; add 1.0% copper(II) sulphate drop by drop shaking the mixture after each dropPurple/violet/mauve colour was observedProtein is presentiii. Smear a drop of mixture A on white paper and observe against light Translucent area/mark observedFats/oil/lipid present.","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2007>1>b","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"b","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Which of the classes of food din mixture A is A is likely to b be absorbed first into the blood stream after digestion?","images":[],"marking_scheme":"Carbohydrate/starch is likely to be absorbed first into the blood stream after digestion","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>1>c>i","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"i","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"For each class of food identified in mixture A: (i) name two local sources;","images":[],"marking_scheme":"Local sources of food classes identified in specimen (mixture) A to the human body: Rice, cassava, maize, millet, yam, potato, plantain, bread, sugar cane, orange, groundnut, mango, banana, any other correct example. Local sources of Protein: Beans meat, egg, fish, groundnut, milk, cheese, peas, sesame seed, any other correct example. Local sources of Fats and Oil: Groundnut, butter, margarine, milk, olive oil, avocado pear, sesame seed, cotton seed, cheese any other correct example","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>1>c>ii","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"ii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"State two uses to the human body.","images":[],"marking_scheme":"Uses of food classes: Carbohydrates:   (1) oxidized to give energy/provides energy.   (2) Starting material for synthesis of lipids and proteins.   (3) Excess stored glycogen for later use. Proteins:   (1) For growth.   (2) For repair/formation of tissues.   (3) Oxidized to give energy/ provides energy.   (4) For synthesis/production of enzymes.   (5) For synthesis of hormones/insulin.   (6) Formation of Mood proteins/fibrinogen.   Fats and Oils:   (1) Oxidized to give energy/provides energy.   (2) Stored under skin/adipose sue/around organs to insulate/prevent loss of heat.   (3) Formation of cell membranes.   (4) Stored as food reserve.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>1>d","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"d","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Name two elements each present in the food classes identified in the mixture A.","images":[],"marking_scheme":"The elements present in the food classes identified in the mixture (specimen) A are as follows:  Proteins - carbon, hydrogen, oxygen, nitrogen, sulphur, phosphorus.  Carbohydrates - carbon, hydrogen, oxygen.   Fats and Oils - carbon, hydrogen, oxygen.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>2>a>i","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Specimen B is a Lizard, specimen C is a grasshopper, specimen D is a grass, specimen E is garden soil and specimen F is a branch of cactus plant.    Mention the habitats of specimens B, C and F.","images":[],"marking_scheme":"Habitats of Specimens B,C, and F: B/Lizard - Around homes/buildings/grasslands/forest trees/trees/concrete abs/rocks. C/Grasshopper - Open grasslands/garden/farms/forest. F/Cactus - Desert/Savanna/Arid regions/sandy Beaches.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>2>a>ii","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State three observable features which adapt specimen F to its environment.","images":[],"marking_scheme":"Structural adaptations of F/Cactus to its environment are:   (1) Leaves are reduced to spines to reduce transpiration/protection.   (2) Stem is succulent/fleshy/has water storage tissues to store/conserve water.  (3) Stem contains chlorophyll for photosynthesis.   (4) Stem has waxy/thick cuticle to reduce water loss/ transpiration.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>2>a>iii","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"iii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Construct a food chain using at least three of the given specimens.","images":[],"marking_scheme":"D/Grass \u2192 C/ Grasshopper \u2192 B/Lizard","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>2>b>i","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Classify specimens B, C, D, E and F into biotic and abiotic Factors.","images":[],"marking_scheme":"Classification of specimens B,C,D,E and F into biotic and abiotic factors: Biotic factors B/Lizard; C/Grasshopper, D/Grass, F/Cactus. Abiotic factor E/Soil","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>2>b>ii","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"What is the significance of specimen E in the ecosystem?","images":[],"marking_scheme":"Significance of E/Garden Soil in the ecosystem:   (1) Supports/anchors plants/medium for plant growth.   (2) Contains water for plant growth.   (3) Contains mineral salts for plant growth.   (4) Contains organic matter/humus which supplies nutrient to plants.   (5) Natural habitat of some organisms.   (6) Contains air for respiration of soil organisms.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>2>c","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"c","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Make a drawing 8 to 10cm long of the lateral view of specimen C and label fully.","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing of specimen C/Grasshopper","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>3>a>i","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : PLANT STRUCTURE","question":"Study carefully specimens Land M.    List three similarities in specimens L and M.","images":[],"marking_scheme":"Specimens L and M both have the following similarities:   (1) Simple leaves.   (2) Leaf edge/margin is entire.   (3) Presence of chlorophyll/green colour in leaves. (4) Presence of veins.   (5) Pointed apexes.   (6) Prominent midrib.   (7) They both have stems.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>3>a>ii","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : PLANT STRUCTURE","question":"State in a tabular form five differences between specimens L and M.","images":[],"marking_scheme":"Specimen L/Cocoa/Fig/Gmelina/Cashew/Avocado PearSpecimen M/Elephant/ grass/Any grass(1) Woody/hard stemHollow/soft stem(2) Oval/broad leaf bladeElongated/Narrow leaf blade(3) Net venationParallel venation(4) Leaf blade flat horizontallyLead blade standing vertically(5) Prominent pulvinus/petiolesNo pulvinus/have sheaths(6) Roots not shownRoots shown(7) A twig/branchWhole plant(8) Internodes clearly seenInternodes covered with sheaths(9) Bark presentBark absent(10) Leaf smoothLeaf hairy","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>3>a>iii","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"iii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Name one ecological zone where each of specimens L and M would be found.","images":[],"marking_scheme":"Ecological zones of specimens Land M: L Cocoa-tropical/rain forest/forest. Specimen M/ Grass-Savannah/Grassland","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2007>3>a>iv","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"iv","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State two observable features each of specimens L and M which e adaptations to the ecological zones mentioned in 4(a)(iii) above","images":[],"marking_scheme":"Observable Features of specimens L and M which adapt them to their ecological zones are:   Specimen L   (1) Broad/oval leaves trap adequate light in dim forest.   (2) Leaves lie flat exposing maximum leaf surface to dim forest light   Specimen M   (1) Erect leaves avoid direct sunlight and subsequent overheating.   (2) Hair reduce rate of transpiration.   (3) Underground rhizome escape burning during bush fires/ survives dry season/drought.   (4) Flexible stem to withstand winds.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>3>b>i","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS","question":"Describe briefly how the density of specimen M can be measured using a quadrat.","images":[],"marking_scheme":"Determining Density of Specimen M using a quadrat:   (1) The area under study is demarcated.   (2) Use a quadrat of known size.   (3) The quadrat is randomly tossed at least 10 times.   (4) The number of wild grasses within the quadrat is calculated by dividing the total number of grass by the number of throws.   (5) The density is determined by dividing the average number of (times wild) grass (occurs) within the quadrat/frequency of grass by the area of the quadrat.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>3>b>ii","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"Name any other instrument that can be used to measure the density of specimen M.","images":[],"marking_scheme":"Line transect","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>3>c>i","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"The table below contains the mean dry weights of plants identical age of an annual crop grown in pots P, Q, R and S. The pots were of the same size and each was altered at a two-day interval with the same volume of water.  PotsNumber of Plants per potMean dry weight per plant (g)P592Q1091R2075S3046  What phenomenon is shown by the data?","images":[],"marking_scheme":"Intra-specific competition is shown by the data in pots PQRS","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>3>c>ii","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"Explain the mean dry weights of plants obtained.","images":[],"marking_scheme":"Explanation of Data: Plants crowded in pot R and S competed for water. light, root space; nutrients","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>3>c>iii","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"iii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"What conclusion can be drawn from the results?","images":[],"marking_scheme":"Conclusion: The competition reduced growth rate of the plants mean dry weight decreased as number of plants per pot increased","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2007>3>c>iv","subject":"Biology Practical","year":"2007","type":"Practical","sub_label":"iv","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"Describe the procedure you would follow to determine the mean dry weight of the plants in one pot.","images":[],"marking_scheme":"Procedure for the determination of Mean Dry Weight of the plants in one pot are:   (1) Uproot the plants carefully to obtain all root parts.   (2) Wash off thoroughly the solid particles adhering to the roots.   (3) Cut up individual plants into separate dishes to allow thorough drying.   (4) Heal the plants in an oven and weigh periodically until a constant weight tis achieved.   (5) Calculate total weight by adding weights of the individual plants   (6) Divide the total by the number of plants obtain the mean dry weight.","marks":"1","difficulty":"2"}];